135→export async function listWorkspaceConflicts(input: WorkspaceQueryInput): Promise<ConflictRow[]> {
136→  const [rows] = await input.surreal
137→    .query<[
138→      Array<{
139→        id: RecordId<"conflicts_with", string>;
140→        in: RecordId<"decision" | "feature", string>;
141→        out: RecordId<"decision" | "feature", string>;
142→        description?: string;
143→        severity?: string;
