183→      fromRecord: row.in,
184→      fromName,
185→      fromKind,
186→      toRecord: row.out,
187→      toName,
188→      toKind,
189→      ...(row.description ? { description: row.description } : {}),
190→      ...(row.severity ? { severity: row.severity } : {}),
191→      detectedAt: row.detected_at ? toIso(row.detected_at) : new Date().toISOString(),
192→    });
193→  }
194→
195→  return results;
196→}
